import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import { useAuth } from "./hooks/useAuth";
import { ComplaintProvider } from "./context/ComplaintContext";
import LoginPage from "./pages/LoginPage";
import HomePage from "./pages/HomePage";
import AcademicPage from "./pages/AcademicPage";
import FoodPage from "./pages/FoodPage";
import LaundryPage from "./pages/LaundryPage";
import ComplaintPage from "./pages/ComplaintPage";
import AdminPage from "./pages/AdminPage";
import Navbar from "./components/Navbar";

function ProtectedLayout({ children }) {
  const { user } = useAuth();

  const backgroundStyle = {
    backgroundImage: `linear-gradient(to bottom, rgba(255, 255, 255, 0.5), rgba(255, 255, 255, 0.65)), url(/bennett.jpg)`,
    backgroundSize: "cover",
    backgroundPosition: "center",
    backgroundAttachment: "fixed",
  };

  return (
    <div className="app-container" style={backgroundStyle}>
      {/* Content Layer */}
      <div className="relative z-10 flex flex-col min-h-screen">
        <Navbar user={user} />
        <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8">
          {children}
        </main>
      </div>
    </div>
  );
}

export default function App() {
  const { user, login, logout, isLoading, error: authError } = useAuth();

  if (!user) {
    return <LoginPage onLogin={login} isLoading={isLoading} authError={authError} />;
  }

  return (
    <ComplaintProvider>
      <Router>
        <Routes>
          <Route
            path="/"
            element={
              <ProtectedLayout>
                <HomePage />
              </ProtectedLayout>
            }
          />
          <Route
            path="/academic"
            element={
              <ProtectedLayout>
                <AcademicPage />
              </ProtectedLayout>
            }
          />
          <Route
            path="/food"
            element={
              <ProtectedLayout>
                <FoodPage />
              </ProtectedLayout>
            }
          />
          <Route
            path="/laundry"
            element={
              <ProtectedLayout>
                <LaundryPage />
              </ProtectedLayout>
            }
          />
          <Route
            path="/complaint"
            element={
              <ProtectedLayout>
                <ComplaintPage />
              </ProtectedLayout>
            }
          />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Router>
    </ComplaintProvider>
  );
}
